import React, { useEffect, useState } from "react";

function AssignmentList() {
  const [assignments, setAssignments] = useState([]);

  const fetchAssignments = async () => {
    const response = await fetch("http://localhost:8080/assignments/user/1");
    const data = await response.json();
    setAssignments(data);
  };

  const markSubmitted = async (id) => {
    await fetch(`http://localhost:8080/assignments/submit/${id}`, {
      method: "PUT",
    });
    fetchAssignments();
  };

  useEffect(() => {
    fetchAssignments();
  }, []);

  return (
    <div>
      <h2>Assignments</h2>
      <ul>
        {assignments.map((a) => (
          <li key={a.id}>
            {a.title} - {a.subject} - Due: {a.dueDate} - Status: {a.status}
            {a.status === "PENDING" && (
              <button onClick={() => markSubmitted(a.id)}>
                Submit
              </button>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default AssignmentList;
